import{_ as i,o as s,c as e,a2 as l}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"产品 Roadmap：从产品小白到独立定义产品","description":"","frontmatter":{},"headers":[],"relativePath":"02-product/roadmap.md","filePath":"02-product/roadmap.md","lastUpdated":1784683277000}'),n={name:"02-product/roadmap.md"};function t(r,a,o,p,h,d){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="产品-roadmap-从产品小白到独立定义产品" tabindex="-1">产品 Roadmap：从产品小白到独立定义产品 <a class="header-anchor" href="#产品-roadmap-从产品小白到独立定义产品" aria-label="Permalink to &quot;产品 Roadmap：从产品小白到独立定义产品&quot;">​</a></h1><p>这是一条适合个人执行的产品学习路线。用户访谈不是必修前提，学习者可以先通过公开证据、产品使用、功能拆解、数据和真实问题日志建立判断，再在有条件时把访谈作为可选验证手段。</p><p>产品能力的核心不是写文档，而是持续回答：为谁解决什么问题、为什么值得解决、如何验证、做什么与不做什么。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户价值 ∩ 商业价值 ∩ 技术可行性 = 可持续的产品机会</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="能力阶梯" tabindex="-1">能力阶梯 <a class="header-anchor" href="#能力阶梯" aria-label="Permalink to &quot;能力阶梯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>能力目标</th><th>代表产出</th></tr></thead><tbody><tr><td>入门</td><td>看懂产品、功能、用户、场景和价值</td><td>产品定位卡</td></tr><tr><td>初级</td><td>能拆解功能并发现有证据的问题</td><td>功能拆解与问题清单</td></tr><tr><td>中级</td><td>能定义需求、MVP、指标和方案</td><td>PRD、原型与验证报告</td></tr><tr><td>高级</td><td>能推动上线、实验、商业与迭代</td><td>Roadmap、数据复盘和商业分析</td></tr><tr><td>专项</td><td>能处理 B 端或 AI 产品复杂性</td><td>权限流程或 AI 产品方案</td></tr></tbody></table><hr><h2 id="阶段零-产品基础语言" tabindex="-1">阶段零：产品基础语言 <a class="header-anchor" href="#阶段零-产品基础语言" aria-label="Permalink to &quot;阶段零：产品基础语言&quot;">​</a></h2><h3 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h3><ul><li>[ ] 产品、项目、功能、服务和平台的区别。</li><li>[ ] 用户、客户、使用者、购买者、决策者和管理员。</li><li>[ ] 用户目标、使用场景、痛点、需求、方案和功能的区别。</li><li>[ ] 用户价值、商业价值、实现成本和机会成本。</li><li>[ ] 产品定位、价值主张、核心能力、辅助能力和产品边界。</li><li>[ ] B2C、B2B、SaaS、平台、工具和内容产品的基本模式。</li><li>[ ] 产品生命周期：发现、定义、设计、开发、发布、度量和迭代。</li></ul><p>定位模板：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我们为【目标用户】，</span></span>
<span class="line"><span>在【特定场景】下，</span></span>
<span class="line"><span>解决【关键问题】，</span></span>
<span class="line"><span>通过【核心方案】，</span></span>
<span class="line"><span>帮助用户获得【最终价值】。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>必做：为五个不同类型的产品制作产品卡，记录定位、角色、核心任务、价值、收费方式、主要成本和风险。</p><p>验收：能清楚回答一个产品为谁服务、解决什么、为什么被选择、如何持续存在以及什么不属于它。</p><hr><h2 id="阶段一-产品观察、思考与拆解" tabindex="-1">阶段一：产品观察、思考与拆解 <a class="header-anchor" href="#阶段一-产品观察、思考与拆解" aria-label="Permalink to &quot;阶段一：产品观察、思考与拆解&quot;">​</a></h2><p>不要只截图和罗列功能。每次拆解从一个具体任务或功能开始，追踪“问题 → 方案 → 交互 → 技术 → 指标 → 商业”的完整链条。</p><ul><li>[ ] 选择一个具体任务，明确入口、前置条件和完成标准。</li><li>[ ] 还原主流程、分支、失败、权限和恢复路径。</li><li>[ ] 推断目标用户、JTBD、使用频率和替代方案。</li><li>[ ] 判断功能提供的用户价值以及对产品目标的作用。</li><li>[ ] 分析默认值、限制、渐进披露和范围取舍。</li><li>[ ] 推断可能的核心指标、守护指标和负面影响。</li><li>[ ] 分析实现成本、运营成本、模型成本或数据依赖。</li><li>[ ] 与两个竞品或非软件替代方案比较。</li><li>[ ] 写出保留、删除、改进各一项，并说明证据与风险。</li></ul><p>验收：连续完成 30 个功能拆解；结论能区分“看见的事实”“基于证据的推断”和“个人观点”。</p><hr><h2 id="阶段二-问题发现与证据收集" tabindex="-1">阶段二：问题发现与证据收集 <a class="header-anchor" href="#阶段二-问题发现与证据收集" aria-label="Permalink to &quot;阶段二：问题发现与证据收集&quot;">​</a></h2><p>个人学习可以使用以下路径，不要求先找到访谈对象：</p><h3 id="公开证据" tabindex="-1">公开证据 <a class="header-anchor" href="#公开证据" aria-label="Permalink to &quot;公开证据&quot;">​</a></h3><ul><li>[ ] 应用商店评论、插件市场评价和公开评分变化。</li><li>[ ] GitHub Issue、Discussion、公开 Roadmap 和 Release Notes。</li><li>[ ] 帮助中心、FAQ、客服公开案例、状态页和已知问题。</li><li>[ ] 公开社区中重复出现的问题、变通方案和迁移原因。</li><li>[ ] 行业报告、公开数据、搜索趋势和政策变化。</li><li>[ ] 竞品定价页、文档、演示、更新日志和下线功能。</li></ul><h3 id="主动观察与实验" tabindex="-1">主动观察与实验 <a class="header-anchor" href="#主动观察与实验" aria-label="Permalink to &quot;主动观察与实验&quot;">​</a></h3><ul><li>[ ] Dogfooding：把自己作为真实用户，记录任务、耗时、错误和绕路。</li><li>[ ] 工作流观察：还原一个任务目前如何用表格、消息、纸笔或多个工具完成。</li><li>[ ] 客服/销售/实施等二手材料：只在合法、脱敏且有权限时使用。</li><li>[ ] Landing Page、原型、假门、问卷或等待名单等低成本验证。</li><li>[ ] 搜索广告、内容点击、开源采用、下载和留存等行为信号。</li><li>[ ] 已有产品的埋点、漏斗、搜索词和失败日志；没有数据时明确标注假设。</li></ul><h3 id="问题表达" tabindex="-1">问题表达 <a class="header-anchor" href="#问题表达" aria-label="Permalink to &quot;问题表达&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当【某类用户】处于【具体场景】时，</span></span>
<span class="line"><span>为了【完成任务或获得进展】，</span></span>
<span class="line"><span>目前使用【现有做法】，</span></span>
<span class="line"><span>但受到【有证据的问题】影响，</span></span>
<span class="line"><span>导致【时间、质量、成本或风险结果】。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>[ ] 写出 JTBD、当前工作流和替代方案。</li><li>[ ] 记录问题频率、严重度、影响范围和证据可信度。</li><li>[ ] 区分症状、根因、需求表达和解决方案请求。</li><li>[ ] 使用多种来源交叉验证，不把单条评论当作普遍事实。</li><li>[ ] 建立“问题证据库”，为每条结论保留来源和日期。</li></ul><p>验收：面对一个想法，先提交问题陈述、证据、当前做法、替代方案和待验证假设，而不是直接列功能。</p><hr><h2 id="阶段三-需求分析与优先级" tabindex="-1">阶段三：需求分析与优先级 <a class="header-anchor" href="#阶段三-需求分析与优先级" aria-label="Permalink to &quot;阶段三：需求分析与优先级&quot;">​</a></h2><p>学习：用户问题、业务目标、产品目标、成功指标、范围、非目标、依赖、风险和上线策略。</p><p>Todo：</p><ul><li>[ ] 明确目标用户和场景。</li><li>[ ] 将功能描述改写为用户问题。</li><li>[ ] 定义业务目标和产品目标。</li><li>[ ] 定义成功指标与守护指标。</li><li>[ ] 明确功能范围和非目标。</li><li>[ ] 识别技术、数据、合规和运营依赖。</li><li>[ ] 使用 RICE 或 Value/Effort 排序。</li><li>[ ] 记录为什么做、为什么不做。</li><li>[ ] 识别最大产品风险。</li></ul><p>需求模板：</p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># 需求分析</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 背景</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 目标用户</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 用户场景</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 用户问题</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 业务目标</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 产品目标</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 成功指标</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 功能范围</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 非目标</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 依赖</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 风险</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 上线策略</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>验收：能有依据地拒绝或延后问题不清、范围过大、价值过低或风险未验证的需求。</p><hr><h2 id="阶段四-产品方案与-mvp" tabindex="-1">阶段四：产品方案与 MVP <a class="header-anchor" href="#阶段四-产品方案与-mvp" aria-label="Permalink to &quot;阶段四：产品方案与 MVP&quot;">​</a></h2><p>学习：方案发散、方案比较、核心假设、低成本验证、MVP 范围、成功与失败标准。</p><p>Todo：</p><ul><li>[ ] 同一问题提出至少三个方案。</li><li>[ ] 比较用户价值、使用成本、开发成本和风险。</li><li>[ ] 找到最关键、最不确定的假设。</li><li>[ ] 设计一周内可以完成的验证。</li><li>[ ] 明确 MVP 核心用户和核心场景。</li><li>[ ] 删除与核心价值无关的功能。</li><li>[ ] 定义继续投入、调整和停止条件。</li></ul><p>验收：能把预计三个月的完整需求，拆成一周验证、两周原型、四周 MVP，再根据数据决定是否扩大。</p><hr><h2 id="阶段五-prd-与产品表达" tabindex="-1">阶段五：PRD 与产品表达 <a class="header-anchor" href="#阶段五-prd-与产品表达" aria-label="Permalink to &quot;阶段五：PRD 与产品表达&quot;">​</a></h2><p>学习：目标、非目标、用户场景、流程、业务规则、异常、验收标准、依赖和上线策略。</p><p>Todo：</p><ul><li>[ ] 写清楚为什么做和不做什么。</li><li>[ ] 使用图表示流程和状态。</li><li>[ ] 写出可验证的用户故事。</li><li>[ ] 使用 Given/When/Then 描述验收条件。</li><li>[ ] 覆盖权限、冲突、失败和边界。</li><li>[ ] 根据产品、设计、开发和测试调整文档内容。</li><li>[ ] 使用 ADR 或决策记录保存重要变化。</li></ul><p>验收：团队阅读后，对目标、范围、规则、异常和完成标准理解一致。</p><hr><h2 id="阶段六-产品数据与实验" tabindex="-1">阶段六：产品数据与实验 <a class="header-anchor" href="#阶段六-产品数据与实验" aria-label="Permalink to &quot;阶段六：产品数据与实验&quot;">​</a></h2><p>学习：北极星指标、过程指标、质量指标、守护指标、漏斗、留存、Cohort、A/B Test、SQL。</p><p>Todo：</p><ul><li>[ ] 定义产品北极星指标。</li><li>[ ] 为核心流程定义漏斗。</li><li>[ ] 设计埋点事件和属性。</li><li>[ ] 区分结果指标和过程指标。</li><li>[ ] 按用户群、版本、来源分析。</li><li>[ ] 识别虚荣指标。</li><li>[ ] 建立产品指标看板。</li><li>[ ] 根据数据提出新的产品假设。</li><li>[ ] 理解相关性与因果关系的区别。</li></ul><p>验收：上线后能回答有多少人使用、哪类用户使用、在哪流失、是否完成目标、是否持续使用，以及是否产生负面影响。</p><hr><h2 id="阶段七-市场、竞品和商业" tabindex="-1">阶段七：市场、竞品和商业 <a class="header-anchor" href="#阶段七-市场、竞品和商业" aria-label="Permalink to &quot;阶段七：市场、竞品和商业&quot;">​</a></h2><p>学习：市场规模、用户类型、购买决策、直接竞品、间接替代、收费、成本、获客、留存、差异化和护城河。</p><p>Todo：</p><ul><li>[x] <a href="./notes/07-market-business/01-market-competition-business-system">分析三个直接竞品</a>。</li><li>[x] <a href="./notes/07-market-business/01-market-competition-business-system">分析两个替代方案</a>。</li><li>[x] <a href="./notes/07-market-business/01-market-competition-business-system">识别使用者、购买者和审批者</a>。</li><li>[x] <a href="./notes/07-market-business/01-market-competition-business-system">分析产品定价与收费方式</a>。</li><li>[x] <a href="./notes/07-market-business/01-market-competition-business-system">分析获客、交付、模型和基础设施成本</a>。</li><li>[x] <a href="./notes/07-market-business/01-market-competition-business-system">理解 MRR、ARR、ARPU、CAC、LTV、Churn、毛利</a>。</li><li>[x] <a href="./notes/07-market-business/01-market-competition-business-system">判断竞品哪些功能不应复制</a>。</li><li>[x] <a href="./notes/07-market-business/01-market-competition-business-system">分析长期差异化和迁移成本</a>。</li></ul><p>验收：能解释产品谁使用、谁付费、为什么付费、如何获客、主要成本、竞争优势和可能被谁替代。</p><hr><h2 id="阶段八-产品推进与持续迭代" tabindex="-1">阶段八：产品推进与持续迭代 <a class="header-anchor" href="#阶段八-产品推进与持续迭代" aria-label="Permalink to &quot;阶段八：产品推进与持续迭代&quot;">​</a></h2><p>学习：目标导向 Roadmap、产品机会、实验、项目、跨团队依赖、灰度、回滚、复盘。</p><p>Todo：</p><ul><li>[x] <a href="./notes/08-delivery-iteration/01-outcome-roadmap-release-postmortem">Roadmap 围绕目标而不是功能列表</a>。</li><li>[x] <a href="./notes/08-delivery-iteration/01-outcome-roadmap-release-postmortem">明确负责人、依赖和风险</a>。</li><li>[x] <a href="./notes/08-delivery-iteration/01-outcome-roadmap-release-postmortem">组织需求、设计和上线评审</a>。</li><li>[x] <a href="./notes/08-delivery-iteration/01-outcome-roadmap-release-postmortem">制定灰度、回滚和通知策略</a>。</li><li>[x] <a href="./notes/08-delivery-iteration/01-outcome-roadmap-release-postmortem">上线后观察指标和用户反馈</a>。</li><li>[x] <a href="./notes/08-delivery-iteration/01-outcome-roadmap-release-postmortem">完成无责复盘和行动项</a>。</li></ul><p>验收：能够推动一个中等复杂度功能完成发现、定义、设计、开发、灰度、数据观察和复盘的闭环。</p><hr><h2 id="阶段九-b-端产品专项" tabindex="-1">阶段九：B 端产品专项 <a class="header-anchor" href="#阶段九-b-端产品专项" aria-label="Permalink to &quot;阶段九：B 端产品专项&quot;">​</a></h2><ul><li>[x] <a href="./notes/09-b2b-products/01-enterprise-domain-permission-workflow-migration">用户角色与权限矩阵</a>。</li><li>[x] <a href="./notes/09-b2b-products/01-enterprise-domain-permission-workflow-migration">核心业务对象与关系</a>。</li><li>[x] <a href="./notes/09-b2b-products/01-enterprise-domain-permission-workflow-migration">状态机和审批流程</a>。</li><li>[x] <a href="./notes/09-b2b-products/01-enterprise-domain-permission-workflow-migration">数据责任、操作日志和合规</a>。</li><li>[x] <a href="./notes/09-b2b-products/01-enterprise-domain-permission-workflow-migration">标准化、配置与定制的边界</a>。</li><li>[x] <a href="./notes/09-b2b-products/01-enterprise-domain-permission-workflow-migration">系统迁移、数据导入和实施流程</a>。</li><li>[x] <a href="./notes/09-b2b-products/01-enterprise-domain-permission-workflow-migration">使用者、管理员、购买者不同的场景</a>。</li></ul><hr><h2 id="阶段十-ai-产品专项" tabindex="-1">阶段十：AI 产品专项 <a class="header-anchor" href="#阶段十-ai-产品专项" aria-label="Permalink to &quot;阶段十：AI 产品专项&quot;">​</a></h2><ul><li>[x] <a href="./notes/10-ai-products/01-ai-product-quality-evaluation-operations">判断 AI 是否真的必要</a>。</li><li>[x] <a href="./notes/10-ai-products/01-ai-product-quality-evaluation-operations">定义 AI 输出质量和不可接受错误</a>。</li><li>[x] <a href="./notes/10-ai-products/01-ai-product-quality-evaluation-operations">设计引用、证据和人工确认</a>。</li><li>[x] <a href="./notes/10-ai-products/01-ai-product-quality-evaluation-operations">评估模型成本、延迟和隐私</a>。</li><li>[x] <a href="./notes/10-ai-products/01-ai-product-quality-evaluation-operations">设计失败降级和人工接管</a>。</li><li>[x] <a href="./notes/10-ai-products/01-ai-product-quality-evaluation-operations">建立真实评估数据集</a>。</li><li>[x] <a href="./notes/10-ai-products/01-ai-product-quality-evaluation-operations">平衡质量、体验、成本和商业模式</a>。</li></ul><hr><h2 id="学习资源" tabindex="-1">学习资源 <a class="header-anchor" href="#学习资源" aria-label="Permalink to &quot;学习资源&quot;">​</a></h2><p>书籍：启示录、用户体验要素、精益创业、用户故事地图、精益数据分析、商业模式新生代、好战略坏战略。</p><p>网站：SVPG、Product Talk、Mind the Product、Lenny’s Newsletter、Reforge、Y Combinator Library、Stratechery、Amplitude Blog、Mixpanel Blog。</p><hr>`,79)])])}const c=i(n,[["render",t]]);export{b as __pageData,c as default};
